CREATE FUNCTION "public"."validate_reservation_against_saved_game"() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO '' AS $$ BEGIN IF NEW.surface = 'bottom'::public.table_surface AND NEW.status = ANY (ARRAY['pending'::public.reservation_status, 'active'::public.reservation_status]) THEN PERFORM pg_catalog.pg_advisory_xact_lock(pg_catalog.hashtextextended(NEW.table_id::text, 0)); IF EXISTS (SELECT 1 FROM public.saved_games WHERE table_id = NEW.table_id AND status = 'active' AND NEW.date BETWEEN start_date AND end_date) THEN RAISE EXCEPTION 'SAVED_GAME_BOTTOM_RESERVED' USING ERRCODE = '23P01'; END IF; END IF; RETURN NEW; END; $$;
